use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract text from a PDF file
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';

    foreach my $page (1 .. $pdf->pages) {
        my $page_content = $pdf->open_page($page);
        my $text_content = $page_content->text();
        $text .= $text_content;
    }

    return $text;
}

# Function to extract specific data from the extracted text
